import pytest
import torch
import ttnn


from .layer_norm import layer_norm


def pytorch_reference(input_tensor, gamma, beta):
    """PyTorch reference for this stage."""
    W = input_tensor.shape[-1]
    return torch.nn.functional.layer_norm(input_tensor, [W], weight=gamma, bias=beta, eps=1e-5)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((1, 1, 128, 64), id="1x1x128x64"),
    ],
)
def test_scale_shift(device, shape):
    """Verify full layer_norm with weight and bias."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    W = torch_input.shape[-1]
    gamma = torch.randn(W)
    beta = torch.randn(W)

    expected = pytorch_reference(torch_input, gamma, beta)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_tile = ttnn.from_torch(gamma.reshape(1, 1, 1, W), dtype=ttnn.bfloat16, layout=ttnn.TILE_LAYOUT, device=device)
    beta_tile = ttnn.from_torch(beta.reshape(1, 1, 1, W), dtype=ttnn.bfloat16, layout=ttnn.TILE_LAYOUT, device=device)

    ttnn_output = layer_norm(ttnn_input, gamma_tile, beta_tile)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
